        links: [{ text: "Leggere insieme per costruire fiducia", href: "https://www.recensionedilibri.it/2022/04/02/zanini-leggere-insieme-per-costruire-fiducia-come-la-lettura-condivisa-favorisce-il-legame-tra-genitori-e-figli/", external: true }],
